.sig-retro-hero {
  position: relative;
  width: min(100%, 980px);
  min-height: 440px;
  display: grid;
  grid-template-columns: minmax(0, 1.08fr) minmax(260px, 0.82fr);
  gap: 34px;
  align-items: stretch;
  padding: 42px;
  overflow: hidden;
  border: 1px solid rgba(242,198,115,0.38);
  border-radius: 12px;
  background: linear-gradient(145deg, #22172b, rgba(247,198,111,0.14));
  color: #fff2d2;
  box-shadow: 0 28px 76px rgba(31,15,35,0.38);
  font-family: JetBrains Mono, ui-monospace, monospace;
}
.sig-retro-hero::before { content: ""; position: absolute; inset: 0; background: repeating-linear-gradient(0deg, rgba(255,242,210,0.045) 0 1px, transparent 1px 5px); background-size: auto; opacity: 0.78; pointer-events: none; }
.sig-retro-hero > * { position: relative; z-index: 1; }
.sig-retro-hero .copy { display: grid; align-content: center; gap: 18px; }
.sig-retro-hero .kicker { width: fit-content; border: 1px solid rgba(242,198,115,0.38); border-radius: 999px; padding: 6px 10px; color: #f2c673; background: rgba(247,198,111,0.14); font-size: 11px; font-weight: 800; text-transform: uppercase; letter-spacing: 0; }
.sig-retro-hero h1 { margin: 0; max-width: 620px; font-family: JetBrains Mono, ui-monospace, monospace; font-size: clamp(40px, 6.4vw, 70px); font-weight: 760; line-height: 0.98; letter-spacing: 0; }
.sig-retro-hero p { margin: 0; max-width: 560px; color: #d8b983; font-size: 15px; line-height: 1.78; }
.sig-retro-hero .actions { display: flex; flex-wrap: wrap; gap: 10px; padding-top: 6px; }
.sig-retro-hero button { height: 40px; padding: 0 16px; border-radius: calc(12px / 2 + 4px); border: 1px solid rgba(242,198,115,0.38); font: inherit; font-size: 13px; font-weight: 700; cursor: pointer; transition: transform 180ms cubic-bezier(0.16, 1, 0.3, 1), border-color 180ms; }
.sig-retro-hero .primary { background: #f2c673; color: #22172b; border-color: #f2c673; }
.sig-retro-hero .secondary { background: transparent; color: #fff2d2; }
.sig-retro-hero button:hover { transform: translateY(-1px); border-color: #f2c673; }
.sig-retro-hero .artifact { display: grid; align-content: space-between; gap: 18px; padding: 22px; border: 1px solid rgba(242,198,115,0.38); border-radius: calc(12px - 2px); background: rgba(247,198,111,0.14); backdrop-filter: blur(18px) saturate(140%); }
.sig-retro-hero .artifact h2 { margin: 0; font-size: 13px; color: #f2c673; text-transform: uppercase; letter-spacing: 0; }
.sig-retro-hero .metric-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; }
.sig-retro-hero .metric { padding: 14px; border: 1px solid rgba(242,198,115,0.38); border-radius: calc(12px - 4px); background: color-mix(in srgb, #22172b 76%, transparent); }
.sig-retro-hero .metric strong { display: block; font-size: 30px; line-height: 1; font-variant-numeric: tabular-nums; }
.sig-retro-hero .metric span { display: block; margin-top: 6px; color: #d8b983; font-size: 11px; }
.sig-retro-hero .rail { height: 9px; border-radius: 999px; background: linear-gradient(90deg, #f2c673, #ff8c6a); }
@media (max-width: 780px) { .sig-retro-hero { grid-template-columns: 1fr; padding: 28px; } }

.sig-retro-card { width: min(100%, 390px); padding: 22px; border: 1px solid rgba(242,198,115,0.38); border-radius: 12px; background: #22172b; color: #fff2d2; box-shadow: 0 28px 76px rgba(31,15,35,0.38); font-family: JetBrains Mono, ui-monospace, monospace; }
.sig-retro-card .top { display: flex; align-items: start; justify-content: space-between; gap: 16px; margin-bottom: 24px; }
.sig-retro-card .label { color: #f2c673; font-size: 12px; font-weight: 800; text-transform: uppercase; letter-spacing: 0; }
.sig-retro-card .pill { border: 1px solid rgba(242,198,115,0.38); border-radius: 999px; padding: 5px 9px; color: #d8b983; background: rgba(247,198,111,0.14); font-size: 11px; }
.sig-retro-card h3 { margin: 0 0 10px; font-family: JetBrains Mono, ui-monospace, monospace; font-size: 32px; line-height: 1; letter-spacing: 0; }
.sig-retro-card p { margin: 0; color: #d8b983; font-size: 13px; line-height: 1.7; }
.sig-retro-card .strip { display: grid; grid-template-columns: 1fr auto; gap: 12px; margin-top: 22px; padding-top: 16px; border-top: 1px solid rgba(242,198,115,0.38); }
.sig-retro-card .strip strong { font-variant-numeric: tabular-nums; color: #fff2d2; }
.sig-retro-card .signal { width: 38px; height: 38px; display: grid; place-items: center; border-radius: calc(12px - 4px); background: #f2c673; color: #22172b; font-weight: 900; }

.sig-retro-nav { width: min(100%, 900px); min-height: 74px; display: flex; align-items: center; justify-content: space-between; gap: 24px; padding: 14px 16px; border: 1px solid rgba(242,198,115,0.38); border-radius: 12px; background: #22172b; color: #fff2d2; box-shadow: 0 28px 76px rgba(31,15,35,0.38); font-family: JetBrains Mono, ui-monospace, monospace; }
.sig-retro-nav .brand { display: flex; align-items: center; gap: 10px; min-width: max-content; font-family: JetBrains Mono, ui-monospace, monospace; font-size: 15px; font-weight: 800; letter-spacing: 0; }
.sig-retro-nav .mark { width: 30px; height: 30px; border-radius: calc(12px - 4px); background: linear-gradient(135deg, #f2c673, #ff8c6a); box-shadow: inset 0 0 0 1px rgba(242,198,115,0.38); }
.sig-retro-nav .links { display: flex; align-items: center; gap: 4px; min-width: 0; overflow-x: auto; }
.sig-retro-nav a { height: 34px; display: inline-flex; align-items: center; padding: 0 12px; border-radius: calc(12px - 6px); color: #d8b983; text-decoration: none; font-size: 13px; transition: color 160ms, background 160ms; white-space: nowrap; }
.sig-retro-nav a:hover, .sig-retro-nav a.active { color: #fff2d2; background: rgba(247,198,111,0.14); }
.sig-retro-nav button { height: 34px; padding: 0 13px; border-radius: calc(12px - 6px); border: 1px solid #f2c673; background: #f2c673; color: #22172b; font: inherit; font-size: 13px; font-weight: 700; cursor: pointer; white-space: nowrap; }
@media (max-width: 720px) { .sig-retro-nav { align-items: stretch; flex-direction: column; } }

.sig-retro-form { width: min(100%, 440px); display: grid; gap: 15px; padding: 22px; border: 1px solid rgba(242,198,115,0.38); border-radius: 12px; background: #22172b; color: #fff2d2; box-shadow: 0 28px 76px rgba(31,15,35,0.38); font-family: JetBrains Mono, ui-monospace, monospace; }
.sig-retro-form label { display: grid; gap: 7px; font-size: 13px; font-weight: 800; color: #fff2d2; }
.sig-retro-form small { color: #d8b983; font-size: 12px; line-height: 1.55; font-weight: 400; }
.sig-retro-form .row { display: flex; gap: 10px; }
.sig-retro-form input { min-width: 0; flex: 1; height: 42px; border-radius: calc(12px - 6px); border: 1px solid rgba(242,198,115,0.38); background: rgba(247,198,111,0.14); color: #fff2d2; padding: 0 12px; font: inherit; outline: none; transition: border-color 160ms, box-shadow 160ms; }
.sig-retro-form input:focus { border-color: #f2c673; box-shadow: 0 0 0 3px color-mix(in srgb, #f2c673 18%, transparent); }
.sig-retro-form button { height: 42px; padding: 0 14px; border-radius: calc(12px - 6px); border: 1px solid #f2c673; background: #f2c673; color: #22172b; font: inherit; font-size: 13px; font-weight: 800; cursor: pointer; }
@media (max-width: 520px) { .sig-retro-form .row { flex-direction: column; } }

.sig-retro-table { width: min(100%, 780px); overflow: hidden; border: 1px solid rgba(242,198,115,0.38); border-radius: 12px; background: #22172b; color: #fff2d2; box-shadow: 0 28px 76px rgba(31,15,35,0.38); font-family: JetBrains Mono, ui-monospace, monospace; }
.sig-retro-table table { width: 100%; border-collapse: collapse; font-size: 13px; }
.sig-retro-table th, .sig-retro-table td { padding: 12px 14px; text-align: left; border-bottom: 1px solid rgba(242,198,115,0.38); }
.sig-retro-table th { color: #d8b983; font-size: 11px; font-weight: 900; text-transform: uppercase; letter-spacing: 0; background: rgba(247,198,111,0.14); }
.sig-retro-table td { color: #fff2d2; }
.sig-retro-table tr:last-child td { border-bottom: 0; }
.sig-retro-table tbody tr:hover td { background: rgba(247,198,111,0.14); }
.sig-retro-table .mono { font-variant-numeric: tabular-nums; }
.sig-retro-table .status { display: inline-flex; align-items: center; gap: 6px; color: #f2c673; font-weight: 800; }
.sig-retro-table .status::before { content: ""; width: 7px; height: 7px; border-radius: 50%; background: #f2c673; }

.bg-film-grain {
  min-height: 100vh;
  background: #0a0a0f;
  position: relative;
}
.bg-film-grain::after {
  content: '';
  position: absolute;
  inset: 0;
  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 400 400' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='g'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23g)'/%3E%3C/svg%3E");
  opacity: 0.02;
  pointer-events: none;
  animation: grain-shift 0.3s steps(6) infinite;
}
@keyframes grain-shift {
  0% { transform: translate(0, 0); }
  33% { transform: translate(-1px, 1px); }
  66% { transform: translate(1px, -1px); }
}

.card-retro-term {
  width: 320px;
  background: #0a0a0a;
  border: 2px solid #33ff33;
  border-radius: 0;
  font-family: 'Courier New', monospace;
  overflow: hidden;
  position: relative;
}
.card-retro-term::after {
  content: '';
  position: absolute;
  inset: 0;
  background: repeating-linear-gradient(0deg, rgba(51,255,51,0.03) 0px, rgba(51,255,51,0.03) 1px, transparent 1px, transparent 3px);
  pointer-events: none;
}
.card-retro-term .header {
  background: #33ff33;
  color: #0a0a0a;
  padding: 4px 8px;
  font-size: 11px;
  font-weight: 700;
}
.card-retro-term .body {
  padding: 16px;
  color: #33ff33;
  font-size: 12px;
  line-height: 1.8;
  text-shadow: 0 0 4px rgba(51,255,51,0.5);
}

.bg-crt {
  min-height: 100vh;
  background: #050505;
  position: relative;
}
.bg-crt::before {
  content: '';
  position: absolute;
  inset: 0;
  background:
    repeating-linear-gradient(0deg, rgba(51,255,51,0.02) 0px, rgba(51,255,51,0.02) 1px, transparent 1px, transparent 3px),
    radial-gradient(ellipse at center, rgba(51,255,51,0.015) 0%, transparent 70%);
  pointer-events: none;
}
.bg-crt::after {
  content: '';
  position: absolute;
  inset: 0;
  background: radial-gradient(ellipse at center, transparent 60%, rgba(0,0,0,0.4) 100%);
  pointer-events: none;
}

.hero-retro-boot {
  min-height: 100vh;
  background: #0a0a0a;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 40px;
}
.hero-retro-boot .screen {
  font-family: 'Courier New', monospace;
  font-size: 14px;
  color: #33ff33;
  line-height: 2;
  text-shadow: 0 0 6px rgba(51,255,51,0.4);
  max-width: 600px;
}
.hero-retro-boot .screen .line {
  opacity: 0;
  animation: boot-line 0.3s ease forwards;
}
.hero-retro-boot .screen .line:nth-child(1) { animation-delay: 0.2s; }
.hero-retro-boot .screen .line:nth-child(2) { animation-delay: 0.6s; }
.hero-retro-boot .screen .line:nth-child(3) { animation-delay: 1.0s; }
.hero-retro-boot .screen .line:nth-child(4) { animation-delay: 1.4s; }
.hero-retro-boot .screen .line:nth-child(5) { animation-delay: 1.8s; }
@keyframes boot-line { to { opacity: 1; } }

.btn-pixel {
  padding: 10px 20px;
  background: #c8c8c8;
  color: #1a1a1a;
  font-family: 'Courier New', monospace;
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 0.05em;
  text-transform: uppercase;
  border: none;
  box-shadow: inset -3px -3px 0 #888, inset 3px 3px 0 #fff;
  cursor: pointer;
  image-rendering: pixelated;
}
.btn-pixel:active {
  box-shadow: inset 3px 3px 0 #888, inset -3px -3px 0 #fff;
  padding: 11px 19px 9px 21px;
}
